'use client';

import { useState } from 'react';

interface Message {
  role: 'user' | 'assistant' | 'system' | 'tool';
  content: string;
  name?: string;
}

export default function ChatPage() {
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'system',
      content: "You are a local developer agent. You have tools to manage files in your workspace. IMPORTANT: Always use simple relative filenames (e.g., 'reverse.py') for the path parameter. NEVER use absolute windows paths starting with C:\\ or system folders.",
    },
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const sendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || loading) return;

    const userMessage: Message = { role: 'user', content: input };
    const updatedMessages = [...messages, userMessage];
    
    setMessages(updatedMessages);
    setInput('');
    setLoading(true);

    try {
      const response = await fetch('http://127.0.0.1:8001/api/agent', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ messages: updatedMessages }),
      });

      if (!response.ok) throw new Error('Failed to connect to agent backend.');
      
      const data = await response.json();
      // Update state with the entire conversational history returned from the agent loop
      setMessages(data.messages);
    } catch (error) {
      console.error(error);
      setMessages((prev) => [
        ...prev,
        { role: 'assistant', content: '❌ Error: Could not reach the local agent server.' },
      ]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-screen bg-gray-900 text-gray-100">
      {/* Header */}
      <header className="p-4 border-b border-gray-800 bg-gray-950 shadow-md">
        <h1 className="text-xl font-bold text-emerald-400 flex items-center gap-2">
          🤖 Next.js Local Agent Workspace
        </h1>
      </header>

      {/* Chat Area */}
      <main className="flex-1 overflow-y-auto p-6 space-y-4 max-w-3xl w-full mx-auto">
        {messages
          .filter((m) => m.role !== 'system')
          .map((msg, index) => {
            if (msg.role === 'tool') {
              return (
                <div key={index} className="text-xs font-mono bg-gray-950 p-2 border border-gray-800 rounded-md text-gray-400">
                  🛠️ Executed Tool [{msg.name}]: {msg.content.slice(0, 120)}...
                </div>
              );
            }
            return (
              <div
                key={index}
                className={`flex gap-3 p-4 rounded-lg max-w-[85%] ${
                  msg.role === 'user'
                    ? 'bg-emerald-600 ml-auto text-white'
                    : 'bg-gray-800 border border-gray-700'
                }`}
              >
                <div>
                  <span className="font-semibold block text-xs opacity-75 mb-1">
                    {msg.role === 'user' ? 'You' : 'Agent'}
                  </span>
                  <p className="whitespace-pre-wrap text-sm">{msg.content}</p>
                </div>
              </div>
            );
          })}
        {loading && (
          <div className="text-sm italic text-gray-400 animate-pulse flex items-center gap-2">
            🧠 Agent is thinking and inspecting workspace files...
          </div>
        )}
      </main>

      {/* Input Tray */}
      <footer className="p-4 border-t border-gray-800 bg-gray-950">
        <form onSubmit={sendMessage} className="max-w-3xl mx-auto flex gap-3">
          <input
            type="text"
            className="flex-1 bg-gray-800 border border-gray-700 rounded-lg px-4 py-3 text-sm focus:outline-none focus:border-emerald-500 text-gray-100"
            placeholder="Ask the agent to build or read something in the workspace..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={loading}
          />
          <button
            type="submit"
            className="bg-emerald-500 hover:bg-emerald-600 disabled:bg-gray-700 text-gray-950 font-medium px-6 py-3 rounded-lg text-sm transition-colors"
            disabled={loading}
          >
            Send
          </button>
        </form>
      </footer>
    </div>
  );
}
